// Command gitproviderd is the stateless HTTP git-provider service. Its wire
// contract is defined in TypeSpec (../../openapi), the strict server is
// generated by oapi-codegen (../../api/openapi), and the handlers live in
// ../../api/v1. The apitoolchain TS gateway calls it server-to-server; provider
// credentials (kind, baseUrl, token, login) are passed per request, so it holds
// no secrets.
package main

import (
	"log"
	"net/http"
	"os"
	"time"

	v1 "github.com/livesession/apitoolchain-gitprovider/api/v1"
)

func main() {
	port := os.Getenv("PORT")
	if port == "" {
		port = "8790"
	}

	srv := &http.Server{
		Addr:              ":" + port,
		Handler:           v1.NewHandler(),
		ReadHeaderTimeout: 10 * time.Second,
	}
	log.Printf("gitproviderd listening on :%s", port)
	if err := srv.ListenAndServe(); err != nil && err != http.ErrServerClosed {
		log.Fatalf("gitproviderd: %v", err)
	}
}
